(function(){
'use strict';
const $=(s,r=document)=>r.querySelector(s);
const API='/api/vehicles';
const state={ready:false,page:1,pageSize:20,search:'',vehicle_type:'',owner_name:'',catalogs:null};
const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));
const num=v=>new Intl.NumberFormat('vi-VN').format(Number(v||0));
const money=v=>new Intl.NumberFormat('vi-VN').format(Number(v||0));
const toast=(m,t='success')=>typeof showToast==='function'?showToast(m,t):console.log(m);
async function req(url,opt={}){ if(typeof api==='function')return api(url,opt); const token=window.App?.token||localStorage.getItem('thon09_token')||''; const init={method:opt.method||'GET',headers:{Accept:'application/json',Authorization:token?'Bearer '+token:''}}; if(opt.body){init.headers['Content-Type']='application/json';init.body=JSON.stringify(opt.body);} const r=await fetch(url,init); const j=await r.json().catch(()=>null); if(!r.ok||j?.ok===false)throw new Error(j?.error?.message||'Không tải được dữ liệu'); return j?.data??j;}
function can(action){const role=(window.App?.user?.role||'').toUpperCase(); if(['SUPER_ADMIN','ADMIN'].includes(role))return true; if(role==='OFFICER')return ['read','create','update'].includes(action); if(role==='VIEWER')return action==='read'; return true;}
document.addEventListener('DOMContentLoaded',init);
document.addEventListener('thon09:screen-change',e=>{if(e.detail?.screen==='vehicles')load();});
function init(){ if($('#vehiclesScreen')?.classList.contains('active'))load(); }
function shell(){
const host=$('#vehiclesScreen'); if(!host||state.ready)return;
host.classList.remove('module-placeholder-screen');
host.innerHTML='<section id="vehiclesStats" class="dashboard-kpi-grid mb-3"></section><section class="content-card module-filter-card"><div class="module-page-head"><div><h2>Quản lý xe cộ</h2><p class="text-muted mb-0">Quản lý phương tiện theo hộ gia đình.</p></div><div class="d-flex gap-2 flex-wrap"><button id="vehicleExportExcel" class="btn btn-outline-success" type="button"><i class="fa-solid fa-file-excel"></i> Excel</button><button id="vehicleExportPdf" class="btn btn-outline-danger" type="button"><i class="fa-solid fa-file-pdf"></i> PDF</button><button id="vehicleAddBtn" class="btn btn-success" type="button"><i class="fa-solid fa-plus"></i> Thêm phương tiện</button></div></div><div class="row g-2"><div class="col-lg-4"><label class="form-label">Tìm kiếm</label><input id="vehicleSearch" class="form-control" placeholder="Mã hộ, chủ hộ, biển số, nhãn hiệu..."></div><div class="col-md-3"><label class="form-label">Loại phương tiện</label><select id="vehicleTypeFilter" class="form-select"><option value="">Tất cả</option></select></div><div class="col-md-3"><label class="form-label">Chủ sở hữu</label><input id="vehicleOwnerFilter" class="form-control" placeholder="Tên chủ sở hữu"></div><div class="col-md-2 d-flex align-items-end gap-2"><button id="vehicleAddBtnInline" class="btn btn-success flex-fill" type="button"><i class="fa-solid fa-plus"></i> Thêm</button><button id="vehicleResetBtn" class="btn btn-outline-secondary flex-fill" type="button"><i class="fa-solid fa-rotate-left"></i> Làm mới</button></div></div></section><section class="module-list-card household-list-card mt-3"><div class="module-list-head"><div><h3>Danh sách phương tiện</h3><span id="vehiclesTotal">Tổng số: 0 phương tiện</span></div><div class="d-flex gap-2 align-items-center"><button id="vehicleAddBtnList" class="btn btn-success btn-sm" type="button"><i class="fa-solid fa-plus"></i> Thêm phương tiện</button><select id="vehiclesPageSize" class="form-select w-auto"><option>20</option><option>50</option><option>100</option></select></div></div><div class="table-responsive"><table class="table module-table align-middle mb-0"><thead><tr><th>STT</th><th>Mã hộ</th><th>Chủ hộ</th><th>Chủ sở hữu</th><th>Loại</th><th>Nhãn hiệu</th><th>Biển số</th><th>Số khung</th><th>Số máy</th><th>Tình trạng</th><th class="text-end">Thao tác</th></tr></thead><tbody id="vehiclesRows"></tbody></table></div><div id="vehiclesPager" class="pager module-pager"></div></section>'+modalHtml();
bind();
state.ready=true;
}
function modalHtml(){return '<div class="modal fade" id="vehicleModal" tabindex="-1"><div class="modal-dialog modal-xl modal-dialog-scrollable"><form id="vehicleForm" class="modal-content"><div class="modal-header"><h5 class="modal-title">Thông tin phương tiện</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="id"><input type="hidden" name="household_id"><div class="row g-3"><div class="col-md-4"><label class="form-label">Mã phương tiện</label><input name="vehicle_code" class="form-control" disabled></div><div class="col-md-4"><label class="form-label">Hộ gia đình</label><input id="vehicleHouseholdSearch" class="form-control" placeholder="Nhập mã hộ hoặc chủ hộ" autocomplete="off" required><div id="vehicleHouseholdList" class="list-group position-absolute shadow d-none" style="z-index:1060;max-height:240px;overflow:auto"></div></div><div class="col-md-4"><label class="form-label">ID nhân khẩu chủ sở hữu</label><input name="owner_citizen_id" type="number" class="form-control" placeholder="Liên kết hồ sơ nhân khẩu"></div><div class="col-md-4"><label class="form-label">Chủ sở hữu</label><input name="owner_name" class="form-control"></div><div class="col-md-4"><label class="form-label">Loại phương tiện</label><select name="vehicle_type" id="vehicleTypeInput" class="form-select" required></select></div><div class="col-md-4"><label class="form-label">Phân loại chi tiết</label><select name="detail_type" id="vehicleDetailTypeInput" class="form-select"></select></div><div class="col-md-3"><label class="form-label">Nhãn hiệu</label><input name="brand" class="form-control"></div><div class="col-md-3"><label class="form-label">Model</label><input name="model" class="form-control"></div><div class="col-md-3"><label class="form-label">Phiên bản</label><input name="version_name" class="form-control"></div><div class="col-md-3"><label class="form-label">Năm sản xuất</label><input name="manufacture_year" type="number" class="form-control"></div><div class="col-md-3"><label class="form-label">Biển kiểm soát</label><input name="license_plate" class="form-control"></div><div class="col-md-3"><label class="form-label">Số khung</label><input name="frame_number" class="form-control"></div><div class="col-md-3"><label class="form-label">Số máy</label><input name="engine_number" class="form-control"></div><div class="col-md-3"><label class="form-label">Màu sơn</label><input name="color" class="form-control"></div><div class="col-md-4"><label class="form-label">Ngày đăng ký</label><input name="registration_date" type="date" class="form-control"></div><div class="col-md-8"><label class="form-label">Nơi đăng ký</label><input name="registration_place" class="form-control"></div><div class="col-md-4"><label class="form-label">Tình trạng sử dụng</label><select name="usage_status" id="vehicleUsageInput" class="form-select"></select></div><div class="col-md-4"><label class="form-label">Có bảo hiểm</label><select name="has_insurance" class="form-select"><option value="0">Không</option><option value="1">Có</option></select></div><div class="col-md-4"><label class="form-label">Hạn bảo hiểm</label><input name="insurance_expiry_date" type="date" class="form-control"></div><div class="col-md-4"><label class="form-label">Có kiểm định</label><select name="has_inspection" class="form-select"><option value="0">Không</option><option value="1">Có</option></select></div><div class="col-md-4"><label class="form-label">Hạn kiểm định</label><input name="inspection_expiry_date" type="date" class="form-control"></div><div class="col-md-4"><label class="form-label">Ảnh toàn xe</label><input name="vehicle_photo_path" class="form-control" placeholder="Đường dẫn ảnh"></div><div class="col-md-6"><label class="form-label">Ảnh biển số</label><input name="plate_photo_path" class="form-control" placeholder="Đường dẫn ảnh"></div><div class="col-md-6"><label class="form-label">Ảnh giấy đăng ký</label><input name="registration_photo_path" class="form-control" placeholder="Đường dẫn ảnh"></div><div class="col-12"><label class="form-label">Ghi chú</label><textarea name="note" class="form-control" rows="2"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Đóng</button><button class="btn btn-success" type="submit">Lưu</button></div></form></div></div>';}
function bind(){
$('#vehicleSearch').addEventListener('input',debounce(e=>{state.search=e.target.value.trim();state.page=1;load();},300));
$('#vehicleTypeFilter').addEventListener('change',e=>{state.vehicle_type=e.target.value;state.page=1;load();});
$('#vehicleOwnerFilter').addEventListener('input',debounce(e=>{state.owner_name=e.target.value.trim();state.page=1;load();},300));
$('#vehiclesPageSize').addEventListener('change',e=>{state.pageSize=Number(e.target.value||20);state.page=1;load();});
$('#vehicleResetBtn').addEventListener('click',()=>{Object.assign(state,{page:1,search:'',vehicle_type:'',owner_name:''});$('#vehicleSearch').value='';$('#vehicleTypeFilter').value='';$('#vehicleOwnerFilter').value='';load();});
['#vehicleAddBtn','#vehicleAddBtnInline','#vehicleAddBtnList'].forEach(sel=>$(sel)?.addEventListener('click',()=>openForm()));
$('#vehicleForm').addEventListener('submit',save);
$('#vehicleHouseholdSearch').addEventListener('input',debounce(searchHouseholds,250));
$('#vehicleExportExcel').addEventListener('click',()=>exportReport('excel'));
$('#vehicleExportPdf').addEventListener('click',()=>exportReport('pdf'));
}
async function catalogs(){ if(state.catalogs)return state.catalogs; state.catalogs=await req(API+'/catalogs',{cacheTtl:60000}); fill('#vehicleTypeFilter',state.catalogs.vehicle_types,'Tất cả'); fill('#vehicleTypeInput',state.catalogs.vehicle_types,'Chọn loại'); fill('#vehicleDetailTypeInput',state.catalogs.detail_types,'Chọn phân loại'); fill('#vehicleUsageInput',state.catalogs.usage_statuses,'Chọn tình trạng'); return state.catalogs; }
function fill(sel,items,first){const el=$(sel); if(!el)return; el.innerHTML='<option value="">'+esc(first)+'</option>'+(items||[]).map(i=>'<option value="'+esc(i.value)+'">'+esc(i.label||i.value)+'</option>').join('');}
function params(){const p=new URLSearchParams({page:state.page,pageSize:state.pageSize}); ['search','vehicle_type','owner_name'].forEach(k=>{if(state[k])p.set(k,state[k]);}); return p;}
async function load(){ if(!can('read'))return; shell(); await catalogs(); try{const data=await req(API+'?'+params().toString(),{cacheTtl:3000}); render(data); dashboard();}catch(e){toast(e.message,'danger');} }
function render(data){const rows=data.items||[]; $('#vehiclesTotal').textContent='Tổng số: '+num(data.total)+' phương tiện'; $('#vehiclesRows').innerHTML=rows.length?rows.map((r,i)=>row(r,(data.page-1)*data.pageSize+i+1)).join(''):'<tr><td colspan="11" class="text-center text-muted py-4">Chưa có dữ liệu phương tiện</td></tr>'; pager(data); if(typeof thon09SyncResponsiveTableLabels==='function')thon09SyncResponsiveTableLabels($('#vehiclesScreen'));}
function row(r,i){const actions=(can('update')?'<button class="btn btn-sm btn-outline-primary me-1" data-edit="'+r.id+'"><i class="fa-solid fa-pen"></i></button>':'')+(can('delete')?'<button class="btn btn-sm btn-outline-danger" data-del="'+r.id+'"><i class="fa-solid fa-trash"></i></button>':''); return '<tr><td>'+i+'</td><td><strong>'+esc(r.vehicle_code||'')+'</strong><div class="small text-muted">'+esc(r.household_code)+'</div></td><td><strong>'+esc(r.head_citizen_name)+'</strong><div class="text-muted small">'+esc(r.address)+'</div></td><td>'+esc(r.owner_name||r.owner_citizen_name||'')+'<div class="small text-muted">'+esc(r.owner_citizen_code||'')+'</div></td><td>'+esc(r.vehicle_type)+'<div class="small text-muted">'+esc(r.detail_type||'')+'</div></td><td>'+esc([r.brand,r.model,r.version_name].filter(Boolean).join(" "))+'</td><td><strong>'+esc(r.license_plate||'')+'</strong></td><td>'+esc(r.frame_number)+'</td><td>'+esc(r.engine_number)+'</td><td><span class="badge text-bg-light">'+esc(r.usage_status_label)+'</span><div class="small text-muted">BH: '+esc(r.insurance_expiry_date||'')+' KĐ: '+esc(r.inspection_expiry_date||'')+'</div></td><td class="text-end">'+actions+'</td></tr>';}
function pager(data){const h=$('#vehiclesPager'),page=Number(data.page||1),total=Number(data.totalPages||1); h.innerHTML='<button class="btn btn-sm btn-outline-secondary" '+(page<=1?'disabled':'')+'>Trước</button><span class="px-2">'+page+' / '+total+'</span><button class="btn btn-sm btn-outline-secondary" '+(page>=total?'disabled':'')+'>Sau</button>'; const b=h.querySelectorAll('button'); b[0].onclick=()=>{state.page--;load();}; b[1].onclick=()=>{state.page++;load();}; $('#vehiclesRows').querySelectorAll('[data-edit]').forEach(b=>b.onclick=()=>openForm(b.dataset.edit)); $('#vehiclesRows').querySelectorAll('[data-del]').forEach(b=>b.onclick=()=>remove(b.dataset.del));}
async function dashboard(){try{const d=await req(API+'/dashboard?'+params().toString(),{cacheTtl:5000}); const m=d.metrics||{}; $('#vehiclesStats').innerHTML=[['Tổng phương tiện',m.total,'xe','fa-car'],['Theo hộ',m.households,'hộ','fa-house'],['Ô tô',m.cars,'xe','fa-car-side'],['Xe máy',m.motorbikes,'xe','fa-motorcycle'],['Xe điện',m.electric,'xe','fa-bolt'],['Có biển số',m.with_plate,'xe','fa-id-card'],['Không biển số',m.without_plate,'xe','fa-circle-question'],['Hết kiểm định',m.expired_inspection,'xe','fa-triangle-exclamation'],['Hết bảo hiểm',m.expired_insurance,'xe','fa-shield-halved']].map(c=>'<article class="dashboard-kpi-card"><span><i class="fa-solid '+c[3]+'"></i></span><div><p>'+c[0]+'</p><strong>'+num(c[1])+'</strong><em>'+c[2]+'</em></div></article>').join('');}catch(e){}}
async function openForm(id){ if(!can(id?'update':'create'))return toast('Tài khoản không có quyền thao tác','warning'); await catalogs(); const f=$('#vehicleForm'); f.reset(); f.elements.id.value=''; f.elements.household_id.value=''; $('#vehicleHouseholdSearch').disabled=false; if(id){const r=await req(API+'/'+id); Object.entries(r).forEach(([k,v])=>{if(f.elements[k])f.elements[k].value=v??'';}); f.elements.id.value=r.id; f.elements.household_id.value=r.household_id; $('#vehicleHouseholdSearch').value=[r.household_code,r.head_citizen_name].filter(Boolean).join(' - '); $('#vehicleHouseholdSearch').disabled=true;} bootstrap.Modal.getOrCreateInstance($('#vehicleModal')).show();}
async function searchHouseholds(e){const q=e.target.value.trim(),list=$('#vehicleHouseholdList'); if(q.length<2){list.classList.add('d-none');return;} const data=await req(API+'/household-search?q='+encodeURIComponent(q)); list.innerHTML=(data.items||[]).map(h=>'<button type="button" class="list-group-item list-group-item-action" data-id="'+h.id+'"><strong>'+esc(h.household_code)+'</strong> - '+esc(h.head_citizen_name)+'<br><small>'+esc(h.address)+'</small></button>').join(''); list.classList.remove('d-none'); list.querySelectorAll('button').forEach(b=>b.onclick=()=>{const h=(data.items||[]).find(x=>String(x.id)===b.dataset.id); $('#vehicleForm').elements.household_id.value=h.id; $('#vehicleHouseholdSearch').value=h.household_code+' - '+h.head_citizen_name; list.classList.add('d-none');});}
async function save(e){e.preventDefault(); const f=e.currentTarget, body=Object.fromEntries(new FormData(f).entries()); try{await req(body.id?API+'/'+body.id:API,{method:body.id?'PUT':'POST',body}); bootstrap.Modal.getOrCreateInstance($('#vehicleModal')).hide(); toast('Đã lưu phương tiện'); load();}catch(err){toast(err.message,'danger');}}
async function remove(id){if(!can('delete'))return toast('Tài khoản không có quyền xóa','warning'); if(!confirm('Xóa phương tiện này?'))return; try{await req(API+'/'+id,{method:'DELETE'}); toast('Đã xóa phương tiện'); load();}catch(e){toast(e.message,'danger');}}
function exportReport(format){const p=params(); p.set('type','vehicles'); window.open((format==='pdf'?'/api/reports/export-pdf':'/api/reports/export-excel')+'?'+p.toString(),'_blank','noopener');}
function debounce(fn,ms){let t;return function(){clearTimeout(t);t=setTimeout(()=>fn.apply(this,arguments),ms);};}
})();
